        close(pipefd[0]); // Close read end in parent

        // Write some data to the pipe
        const char *data = "Hello from parent process!";
        write(pipefd[1], data, strlen(data) + 1);

        // Close the write end
        close(pipefd[1]);

        // Wait for the child to finish
        wait(NULL);

        return 0;
    }
}
